package com.hospital.management.filter;
import com.hospital.management.dao.AuditLogDao;import com.hospital.management.dao.impl.AuditLogDaoImpl;import com.hospital.management.model.AuthenticatedUser;import javax.servlet.*;import javax.servlet.annotation.WebFilter;import javax.servlet.http.*;import java.io.IOException;import java.util.*;
@WebFilter(urlPatterns={"/admin/*","/doctor/*","/nurse/*","/reception/*","/patient/*","/billing/*"}) public class RoleAuthorizationFilter implements Filter {private static final Map<String,Set<String>> ACCESS=Map.of("/admin/",Set.of("ADMIN"),"/doctor/",Set.of("DOCTOR","ADMIN"),"/nurse/",Set.of("NURSE","ADMIN"),"/reception/",Set.of("RECEPTIONIST","ADMIN"),"/patient/",Set.of("PATIENT","ADMIN"),"/billing/",Set.of("BILLING_STAFF","ADMIN"));private final AuditLogDao audit;public RoleAuthorizationFilter(){this(new AuditLogDaoImpl());}public RoleAuthorizationFilter(AuditLogDao audit){this.audit=audit;}public void doFilter(ServletRequest a,ServletResponse b,FilterChain c)throws IOException,ServletException{HttpServletRequest q=(HttpServletRequest)a;HttpServletResponse r=(HttpServletResponse)b;HttpSession s=q.getSession(false);if(s==null||!(s.getAttribute("authenticatedUser") instanceof AuthenticatedUser)){r.sendRedirect(q.getContextPath()+"/login");return;}AuthenticatedUser u=(AuthenticatedUser)s.getAttribute("authenticatedUser");String path=q.getRequestURI().substring(q.getContextPath().length());boolean allowed=ACCESS.entrySet().stream().filter(e->path.startsWith(e.getKey())).allMatch(e->e.getValue().contains(u.getRoleName()));if(!allowed){audit.recordEvent("ACCESS_DENIED",u.getUserId(),"PATH",null,q.getRemoteAddr(),q.getHeader("User-Agent"));r.sendError(HttpServletResponse.SC_FORBIDDEN);return;}c.doFilter(a,b);}}
